/**
 * vCard Generation — Contact download for Space Hub
 */

export const VCARD_STRING = `BEGIN:VCARD
VERSION:3.0
FN:George
ORG:Space Hub
TITLE:Strategic Advisor — Ex-Booz Allen Hamilton
TEL;TYPE=WORK,VOICE:+40745096191
EMAIL;TYPE=PREF,INTERNET:projects@spacehub.ro
URL:https://spacehub.ro
ADR;TYPE=WORK:;;Strada Uranus 33;Varteju;Ilfov;;Romania
NOTE:Strategy consultancy — Defense, Space Tech, Big Data, AI Influence. Magurele / Laser Valley, Romania.
END:VCARD`;

export function downloadVCard(): void {
  const blob = new Blob([VCARD_STRING], { type: 'text/vcard;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'George_SpaceHub.vcf';
  document.body.appendChild(a);
  a.click();
  setTimeout(() => {
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, 100);
}

