/* ============================================================
   SPACE HUB — Military Surveillance Terminal
   ============================================================ */

:root {
  --bg: #000000;
  --green: #00ff41;
  --green-dim: #00aa2a;
  --green-faint: rgba(0,255,65,0.15);
  --green-ghost: rgba(0,255,65,0.05);
  --text: #00ff41;
  --text-dim: #007a20;
  --text-muted: #004a12;
  --warm: #c8a96e;
  --font-mono: 'SF Mono', 'Monaco', 'Cascadia Code', 'Fira Code', monospace;
}

*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html, body {
  width: 100%;
  height: 100%;
  overflow: hidden;
  font-family: var(--font-mono);
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* ── Globe ────────────────────────────────────────────────── */
#globe-container {
  position: fixed;
  top: 0; left: 0;
  width: 100%; height: 100%;
  z-index: 1;
  background: #000;
}

#globe-container canvas {
  position: absolute;
  top: 0; left: 0;
  width: 100% !important;
  height: 100% !important;
}

/* ── Vignette ─────────────────────────────────────────────── */
.vignette {
  position: fixed;
  inset: 0;
  z-index: 5;
  pointer-events: none;
  background: radial-gradient(ellipse at center, transparent 40%, rgba(0,0,0,0.7) 100%);
}

/* ── HUD ──────────────────────────────────────────────────── */
#hud {
  position: fixed;
  inset: 0;
  z-index: 10;
  pointer-events: none;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}

/* ── HUD Top Bar ──────────────────────────────────────────── */
.hud-top {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding: 20px;
  pointer-events: auto;
}

.hud-ident {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.hud-ident-name {
  font-size: 14px;
  font-weight: 700;
  color: var(--green);
  letter-spacing: 0.15em;
  text-transform: uppercase;
}

.hud-ident-sub {
  font-size: 9px;
  color: var(--text-dim);
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

.hud-ident-status {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-top: 4px;
  font-size: 9px;
  color: var(--green-dim);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.status-dot {
  display: inline-block;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--green);
  box-shadow: 0 0 6px var(--green);
  animation: pulse-dot 2s ease-in-out infinite;
}

@keyframes pulse-dot {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

.hud-coords {
  text-align: right;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.hud-coords-latlng {
  font-size: 10px;
  color: var(--text-dim);
  letter-spacing: 0.08em;
}

.hud-coords-clock {
  font-size: 11px;
  color: var(--green);
  letter-spacing: 0.08em;
}

/* ── HUD Bottom ───────────────────────────────────────────── */
.hud-bottom {
  display: flex;
  justify-content: space-between;
  align-items: flex-end;
  padding: 20px;
  pointer-events: auto;
}

/* ── Identity Block ───────────────────────────────────────── */
.identity-block {
  max-width: 440px;
}

.id-name {
  font-size: 22px;
  font-weight: 700;
  color: var(--warm);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.id-title {
  font-size: 11px;
  color: var(--green-dim);
  letter-spacing: 0.06em;
  margin-top: 2px;
}

.id-tagline {
  font-size: 10px;
  color: var(--text-dim);
  letter-spacing: 0.04em;
  margin-top: 4px;
}

.id-location {
  font-size: 9px;
  color: var(--text-muted);
  letter-spacing: 0.06em;
  margin-top: 2px;
}

/* ── Phone ────────────────────────────────────────────────── */
.id-phone {
  margin-top: 6px;
}

.phone-link {
  color: var(--green);
  text-decoration: none;
  font-size: 11px;
  letter-spacing: 0.06em;
  transition: color 0.15s;
}

.phone-link:hover {
  color: var(--warm);
}

/* ── Actions Column (QR + buttons) ────────────────────────── */
.actions-col {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 14px;
}

/* ── QR Code Block ────────────────────────────────────────── */
.qr-block {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 6px;
  padding: 10px;
  border: 1px solid rgba(0,255,65,0.12);
  background: rgba(0,0,0,0.6);
}

.qr-label {
  font-size: 8px;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-dim);
}

#qr-code {
  width: 120px;
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
}

#qr-code svg {
  width: 120px;
  height: 120px;
}

/* ── Services List ────────────────────────────────────────── */
.services-list {
  margin-top: 14px;
  display: flex;
  flex-direction: column;
  gap: 0;
}

.svc-item {
  display: block;
  text-decoration: none;
  color: var(--green-dim);
  font-size: 10px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 5px 0 5px 8px;
  border-left: 2px solid transparent;
  transition: border-color 0.15s ease, color 0.15s ease;
  cursor: pointer;
  position: relative;
}

.svc-item:hover {
  color: var(--green);
  border-left-color: var(--green);
}

.svc-item .svc-label {
  display: inline;
}

.svc-item .svc-desc {
  display: block;
  font-size: 9px;
  color: var(--text-dim);
  letter-spacing: 0.02em;
  text-transform: none;
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.15s ease, margin 0.15s ease;
  margin-top: 0;
}

.svc-item:hover .svc-desc {
  max-height: 40px;
  margin-top: 3px;
}

/* ── Action Buttons ───────────────────────────────────────── */
.actions-block {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: flex-end;
}

.action-btn {
  pointer-events: auto;
  background: transparent;
  border: 1px solid var(--green-dim);
  color: var(--green);
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 6px 14px;
  cursor: pointer;
  transition: background 0.15s ease, border-color 0.15s ease;
  text-decoration: none;
  display: inline-block;
  white-space: nowrap;
}

.action-btn:hover {
  background: var(--green-ghost);
  border-color: var(--green);
}

.action-btn:active {
  background: var(--green-faint);
}

/* ── Classification Bar ───────────────────────────────────── */
.classification-bar {
  position: fixed;
  bottom: 0;
  left: 0;
  width: 100%;
  z-index: 10;
  text-align: center;
  font-family: var(--font-mono);
  font-size: 9px;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-muted);
  padding: 6px 0;
  pointer-events: none;
}

/* ── Station markers (globe) ──────────────────────────────── */
.station-marker {
  position: relative;
  width: 8px; height: 8px;
  cursor: pointer;
  pointer-events: auto;
}

.station-dot {
  width: 8px; height: 8px;
  border-radius: 50%;
  background: var(--green);
  border: 1.5px solid rgba(0,255,65,0.5);
  box-shadow: 0 0 6px 2px rgba(0,255,65,0.4);
}

.station-pulse {
  position: absolute;
  inset: -6px;
  border-radius: 50%;
  background: rgba(0,255,65,0.15);
  animation: globe-pulse 2.5s ease-out infinite;
}

.station-hq .station-dot {
  background: var(--warm);
  border-color: rgba(200,169,110,0.6);
  box-shadow: 0 0 8px 2px rgba(200,169,110,0.5);
}

.station-hq .station-pulse {
  background: rgba(200,169,110,0.15);
}

.station-tooltip {
  position: absolute;
  bottom: 18px; left: 50%;
  transform: translateX(-50%);
  background: rgba(0,0,0,0.85);
  border: 1px solid var(--green-dim);
  padding: 6px 10px;
  white-space: nowrap;
  font-family: var(--font-mono);
  font-size: 9px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--green);
  opacity: 0;
  transition: opacity 0.15s;
  pointer-events: none;
}

.station-marker:hover .station-tooltip {
  opacity: 1;
}

@keyframes globe-pulse {
  0% { transform: scale(1); opacity: 0.6; }
  100% { transform: scale(3); opacity: 0; }
}

/* ── Responsive: Mobile ───────────────────────────────────── */
@media (max-width: 768px) {
  .hud-top {
    flex-direction: column;
    gap: 10px;
    padding: 16px;
  }

  .hud-coords {
    text-align: left;
  }

  .hud-bottom {
    flex-direction: column;
    align-items: flex-start;
    gap: 16px;
    padding: 16px;
    padding-bottom: 28px;
  }

  .identity-block {
    max-width: 100%;
  }

  .id-name { font-size: 18px; }
  .id-title { font-size: 10px; }
  .svc-item { font-size: 9px; }

  /* Hide QR on mobile — can't scan your own phone */
  .qr-block {
    display: none;
  }

  .actions-col {
    width: 100%;
    align-items: flex-start;
  }

  .actions-block {
    flex-direction: row;
    flex-wrap: wrap;
    align-items: flex-start;
    width: 100%;
  }

  .action-btn {
    font-size: 9px;
    padding: 5px 10px;
  }

  .classification-bar {
    font-size: 8px;
    padding: 4px 0;
  }
}

/* ── Reduced motion ───────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .station-pulse { animation: none; }
  .status-dot { animation: none; }
}

