/**
 * Ground Station Data — Space Hub operational presence
 * Marker pattern extracted from GlobeMap.ts:659-678
 */

export interface Station {
  id: string;
  city: string;
  lat: number;
  lng: number;
  role: string;
  isHQ?: boolean;
}

export const STATIONS: Station[] = [
  { id: 'SH-BUC-01', city: 'BUCHAREST',  lat: 44.4326, lng: 26.1038, role: 'HQ — MAGURELE',     isHQ: true },
  { id: 'SH-BRU-01', city: 'BRUSSELS',   lat: 50.8503, lng: 4.3517,  role: 'EU / NATO LIAISON'  },
  { id: 'SH-WDC-01', city: 'WASHINGTON', lat: 38.8951, lng: -77.0364, role: 'US DEFENSE'         },
  { id: 'SH-LON-01', city: 'LONDON',     lat: 51.5074, lng: -0.1278, role: 'INTEL COMMUNITY'    },
  { id: 'SH-TLV-01', city: 'TEL AVIV',   lat: 32.0853, lng: 34.7818, role: 'TECH / DEFENSE'     },
  { id: 'SH-SIN-01', city: 'SINGAPORE',  lat: 1.3521,  lng: 103.8198, role: 'APAC NODE'         },
];

export function buildStationElement(station: Station): HTMLElement {
  const el = document.createElement('div');
  el.className = `station-marker${station.isHQ ? ' station-hq' : ''}`;
  el.innerHTML = `
    <div class="station-pulse"></div>
    <div class="station-dot"></div>
    <div class="station-tooltip">${station.id} // ${station.role}</div>
  `;
  return el;
}

