1	/**
2	 * Communication Arcs — Space Hub operational network
3	 * Arc pattern extracted from GlobeMap.ts:542-559
4	 */
5	
6	import { STATIONS, type Station } from './stations';
7	
8	export interface CommArc {
9	  startLat: number;
10	  startLng: number;
11	  endLat: number;
12	  endLng: number;
13	  color: [string, string, string];
14	}
15	
16	/** Generate arcs connecting HQ to all other stations, plus select inter-station arcs */
17	export function generateArcs(): CommArc[] {
18	  const hq = STATIONS.find(s => s.isHQ)!;
19	  const others = STATIONS.filter(s => !s.isHQ);
