/**
 * Communication Arcs — Space Hub operational network
 * Arc pattern extracted from GlobeMap.ts:542-559
 */

import { STATIONS, type Station } from './stations';

export interface CommArc {
  startLat: number;
  startLng: number;
  endLat: number;
  endLng: number;
  color: [string, string, string];
}

/** Generate arcs connecting HQ to all other stations, plus select inter-station arcs */
export function generateArcs(): CommArc[] {
  const hq = STATIONS.find(s => s.isHQ)!;
  const others = STATIONS.filter(s => !s.isHQ);

  // HQ → all stations
  const hqArcs: CommArc[] = others.map(s => makeArc(hq, s, 'primary'));

  // Inter-station links (select pairs for visual density)
  const interPairs: [string, string][] = [
    ['BRUSSELS', 'WASHINGTON'],
    ['LONDON', 'WASHINGTON'],
    ['BRUSSELS', 'LONDON'],
    ['TEL AVIV', 'SINGAPORE'],
    ['WASHINGTON', 'SINGAPORE'],
  ];

  const interArcs: CommArc[] = interPairs
    .map(([a, b]) => {
      const sa = STATIONS.find(s => s.city === a);
      const sb = STATIONS.find(s => s.city === b);
      if (sa && sb) return makeArc(sa, sb, 'secondary');
      return null;
    })
    .filter((a): a is CommArc => a !== null);

  return [...hqArcs, ...interArcs];
}

function makeArc(from: Station, to: Station, type: 'primary' | 'secondary'): CommArc {
  // Color gradients from World Monitor — tri-color (faded ends, bright center)
  const colors: Record<string, [string, string, string]> = {
    primary: ['rgba(68,136,255,0.05)', 'rgba(68,136,255,0.5)', 'rgba(68,136,255,0.05)'],
    secondary: ['rgba(0,212,255,0.03)', 'rgba(0,212,255,0.25)', 'rgba(0,212,255,0.03)'],
  };

  return {
    startLat: from.lat,
    startLng: from.lng,
    endLat: to.lat,
    endLng: to.lng,
    color: colors[type],
  };
}

