  if (globeMat) {
    globeMat.color = new THREE.Color(0x0a1a0a);
    globeMat.emissive = new THREE.Color(0x002200);
    globeMat.emissiveIntensity = 1.0;
    if (globeMat.map) globeMat.map = null;
    if (globeMat.bumpMap) globeMat.bumpMap = null;
    globeMat.needsUpdate = true;
  }

  /* ── Canvas styling ─────────────────────────────────────── */
  const canvas = container.querySelector('canvas');
  if (canvas) {
    (canvas as HTMLElement).style.cssText =
      'position:absolute;top:0;left:0;width:100%!important;height:100%!important;';
