import { downloadVCard, VCARD_STRING } from './vcard';

interface Service {
  code: string;
  desc: string;
  url: string;
}

const SERVICES: Service[] = [
  {
    code: 'STRATEGY',
    desc: 'Public sector, private sector & academia advisory. Building high-tech ecosystems to drive economic growth.',
    url: 'https://spacehub.ro/strategy/',
  },
  {
    code: 'DESIGN',
    desc: 'CATIA V5 engineering, orbital nanosatellite launchers, CubeSat active stabilization, satellite Big Data analytics.',
    url: 'https://spacehub.ro/design/',
  },
  {
    code: 'INCUBATOR',
    desc: 'Space startup incubator in Laser Valley, Magurele. CubeSat facilities, clean rooms, ground stations.',
    url: 'https://spacehub.ro/incubator/',
  },
  {
    code: 'FINANCING',
    desc: 'M&A advisory for space sector. Crowd-financing for Romanian hi-tech startups.',
    url: 'https://spacehub.ro/financing/',
  },
  {
    code: 'MARKETING',
    desc: 'AI-based digital influence campaigns. Strategic positioning for foreign capital attraction.',
    url: 'https://spacehub.ro/marketing/',
  },
  {
    code: 'RELOCATION',
    desc: 'Full relocation services for UK space companies affected by Brexit.',
    url: 'https://spacehub.ro/relocation/',
  },
];

const PHONE = '+40745096191';

export function createHUD(): HTMLElement {
  const hud = document.getElementById('hud')!;

  const servicesHTML = SERVICES.map(
    (s) => `<a class="svc-item" href="${s.url}" target="_blank" rel="noopener">
      <span class="svc-label">${s.code}</span>
      <span class="svc-desc">${s.desc}</span>
    </a>`
  ).join('');

  hud.innerHTML = `
    <div class="hud-top">
      <div class="hud-ident">
        <div class="hud-ident-name">SPACE HUB</div>
        <div class="hud-ident-sub">Surveillance Terminal</div>
        <div class="hud-ident-status"><span class="status-dot"></span> ACTIVE</div>
      </div>
      <div class="hud-coords">
        <div class="hud-coords-latlng">44.3411°N  26.1038°E</div>
        <div class="hud-coords-clock" id="utc-clock">UTC 00:00:00</div>
      </div>
    </div>

    <div class="hud-bottom">
      <div class="identity-block">
        <div class="id-name">George</div>
        <div class="id-title">Strategic Advisor // Ex-Booz Allen Hamilton</div>
        <div class="id-tagline">Space Hub — Putting you on the right orbit.</div>
        <div class="id-location">Laser Valley, Magurele, Romania</div>
        <div class="id-phone">
          <a href="tel:${PHONE}" class="phone-link">${PHONE}</a>
        </div>
        <div class="services-list">
          ${servicesHTML}
        </div>
      </div>
      <div class="actions-col">
        <div class="qr-block" id="qr-container">
          <div class="qr-label">SCAN TO SAVE</div>
          <div id="qr-code"></div>
        </div>
        <div class="actions-block">
          <button class="action-btn" id="btn-save">SAVE CONTACT</button>
          <a class="action-btn" href="tel:${PHONE}" class="mobile-call">CALL</a>
          <a class="action-btn" href="mailto:projects@spacehub.ro">EMAIL</a>
          <a class="action-btn" href="https://spacehub.ro" target="_blank" rel="noopener">SPACEHUB.RO</a>
        </div>
      </div>
    </div>

    <div class="classification-bar">UNCLASSIFIED // FOUO — SPACE HUB MAGURELE-VARTEJU</div>
  `;

  // Wire save contact
  const btnSave = document.getElementById('btn-save')!;
  btnSave.addEventListener('click', () => {
    downloadVCard();
    btnSave.textContent = 'SAVED';
    btnSave.style.borderColor = 'var(--green)';
    setTimeout(() => {
      btnSave.textContent = 'SAVE CONTACT';
      btnSave.style.borderColor = '';
    }, 2000);
  });

  // Generate QR code (desktop only — CSS hides on mobile)
  generateQR();

  return hud;
}

async function generateQR(): Promise<void> {
  const container = document.getElementById('qr-code');
  if (!container) return;

  try {
    const QRCode = await import('qrcode');
    const svg = await QRCode.toString(VCARD_STRING, {
      type: 'svg',
      width: 120,
      margin: 0,
      color: {
        dark: '#00ff41',
        light: '#00000000', // transparent background
      },
      errorCorrectionLevel: 'M',
    });
    container.innerHTML = svg;
  } catch (e) {
    console.warn('[QR] Failed to generate:', e);
    container.style.display = 'none';
  }
}

export function startClock(): void {
  const el = document.getElementById('utc-clock');
  if (!el) return;

  const tick = () => {
    const now = new Date();
    el.textContent = `UTC ${now.toISOString().slice(11, 19)}`;
  };

  tick();
  setInterval(tick, 1000);
}

