interface Service {
  code: string;
  desc: string;
  url: string;
}

const SERVICES: Service[] = [
  {
    code: 'APEX OS',
    desc: 'Sovereign AI operating system — 6 persistent agents, 49 repos, 70+ skills. Replace process with protocol.',
    url: 'https://apex.infoacademy.uk',
  },
  {
    code: 'INFOACADEMY',
    desc: 'AI learning platform — 163+ daily content items, 20K+ learners, webinars, agentic training.',
    url: 'https://www.infoacademy.uk',
  },
  {
    code: 'PROFILESENSE',
    desc: 'White-label Benelux recruitment intelligence — elevator technician sourcing, AI-scored talent pipeline.',
    url: 'https://profilesense-dashboard.vercel.app',
  },
  {
    code: 'LEAD INTELLIGENCE',
    desc: '19,400+ company database, decision-maker discovery, SMTP verification, AI scoring engine, Telegram alerts.',
    url: 'https://leadgen-platform.vercel.app',
  },
  {
    code: 'WHATSAPP AUTOMATION',
    desc: 'Multi-session NestJS + Baileys gateway. AI concierge, voice notes, photo matching, 24/7 multilingual.',
    url: 'https://apex-os-vibe.vercel.app',
  },
  {
    code: 'WORLD MONITOR',
    desc: 'Regional intelligence platform — geopolitical signals, strategic foresight, defense-grade situational awareness.',
    url: 'https://worldmonitor.app',
  },
];

const PHONE = '+447778424242';

export function createHUD(): HTMLElement {
  const hud = document.getElementById('hud')!;

  const servicesHTML = SERVICES.map(
    (s) => `<a class="svc-item" href="${s.url}" target="_blank" rel="noopener">
      <span class="svc-label">${s.code}</span>
      <span class="svc-desc">${s.desc}</span>
    </a>`
  ).join('');

  hud.innerHTML = `
    <div class="hud-top">
      <div class="hud-ident">
        <div class="hud-ident-name">APEX OS</div>
        <div class="hud-ident-sub">Command Terminal</div>
        <div class="hud-ident-status"><span class="status-dot"></span> ACTIVE — 6 AGENTS ONLINE</div>
      </div>
      <div class="hud-coords">
        <div class="hud-coords-latlng">51.5074°N  0.1278°W</div>
        <div class="hud-coords-clock" id="utc-clock">UTC 00:00:00</div>
      </div>
    </div>

    <div class="hud-bottom">
      <div class="identity-block">
        <div class="id-name">Nico Fratila</div>
        <div class="id-title">Founder & CEO // APEX OS — Sovereign AI Infrastructure</div>
        <div class="id-tagline">If an agent can do it, no human should have to.</div>
        <div class="id-location">London, UK / Bucharest, RO</div>
        <div class="id-phone">
          <a href="tel:${PHONE}" class="phone-link">${PHONE}</a>
        </div>
        <div class="id-social">
          <a class="social-link" href="https://linkedin.com/in/nicofratila" target="_blank" rel="noopener">LINKEDIN</a>
          <a class="social-link" href="https://github.com/fratilanico" target="_blank" rel="noopener">GITHUB</a>
          <a class="social-link" href="https://x.com/nicofratila" target="_blank" rel="noopener">X</a>
        </div>
        <div class="services-list">
          ${servicesHTML}
        </div>
      </div>
      <div class="actions-col">
        <div class="qr-block" id="qr-container">
          <div class="qr-label">SCAN TO SAVE</div>
          <div id="qr-code"></div>
        </div>
        <div class="actions-block">
          <button class="action-btn" id="btn-save">SAVE CONTACT</button>
          <a class="action-btn" href="tel:${PHONE}">CALL</a>
          <a class="action-btn" href="mailto:admin@infoacademy.uk">EMAIL</a>
          <a class="action-btn" href="https://www.infoacademy.uk" target="_blank" rel="noopener">INFOACADEMY.UK</a>
          <a class="action-btn" href="https://apex.infoacademy.uk" target="_blank" rel="noopener">APEX OS</a>
        </div>
      </div>
    </div>

    <div class="classification-bar">APEX OS // NFG DIGITAL SOLUTIONS LTD — LONDON, UK</div>
  `;

  // Wire save contact
  const btnSave = document.getElementById('btn-save')!;
  btnSave.addEventListener('click', () => {
    downloadVCard();
    btnSave.textContent = 'SAVED';
    btnSave.style.borderColor = 'var(--green)';
    setTimeout(() => {
      btnSave.textContent = 'SAVE CONTACT';
      btnSave.style.borderColor = '';
    }, 2000);
  });

  // Generate QR code (desktop only — CSS hides on mobile)
  generateQR();

  return hud;
}

async function generateQR(): Promise<void> {
  const container = document.getElementById('qr-code');
  if (!container) return;

  try {
    const QRCode = await import('qrcode');
    const svg = await QRCode.toString(VCARD_STRING, {
      type: 'svg',
      width: 120,
      margin: 0,
      color: {
        dark: '#00ff41',
        light: '#00000000', // transparent background
      },
      errorCorrectionLevel: 'M',
    });
    container.innerHTML = svg;
  } catch (e) {
    console.warn('[QR] Failed to generate:', e);
    container.style.display = 'none';
  }
}

export function startClock(): void {
  const el = document.getElementById('utc-clock');
  if (!el) return;

  const tick = () => {
    const now = new Date();
    el.textContent = `UTC ${now.toISOString().slice(11, 19)}`;
  };

  tick();
  setInterval(tick, 1000);
}

