.services-list {
  margin-top: 14px;
  display: flex;
  flex-direction: column;
  gap: 0;
}

.svc-item {
  display: block;
  text-decoration: none;
  color: var(--green-dim);
  font-size: 10px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 5px 0 5px 8px;
  border-left: 2px solid transparent;
  transition: border-color 0.15s ease, color 0.15s ease;
  cursor: pointer;
  position: relative;
}

.svc-item:hover {
  color: var(--green);
  border-left-color: var(--green);
}

.svc-item .svc-label {
  display: inline;
}

.svc-item .svc-desc {
  display: block;
  font-size: 9px;
  color: var(--text-dim);
  letter-spacing: 0.02em;
  text-transform: none;
  max-height: 0;
  overflow: hidden;
  transition: max-height 0.15s ease, margin 0.15s ease;
  margin-top: 0;
}

.svc-item:hover .svc-desc {
  max-height: 40px;
  margin-top: 3px;
}

