.actions-block {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: flex-end;
}

.action-btn {
  pointer-events: auto;
  background: transparent;
  border: 1px solid var(--green-dim);
  color: var(--green);
  font-family: var(--font-mono);
  font-size: 10px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 6px 14px;
  cursor: pointer;
  transition: background 0.15s ease, border-color 0.15s ease;
  text-decoration: none;
  display: inline-block;
  white-space: nowrap;
}

.action-btn:hover {
  background: var(--green-ghost);
  border-color: var(--green);
}

.action-btn:active {
  background: var(--green-faint);
}

/* ── Classification Bar ───────────────────────────────────── */
.classification-bar {
  position: fixed;
  bottom: 0;
  left: 0;
  width: 100%;
  z-index: 10;
  text-align: center;
  font-family: var(--font-mono);
  font-size: 9px;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: var(--text-muted);
  padding: 6px 0;
  pointer-events: none;
}

/* ── Station markers (globe) ──────────────────────────────── */
.station-marker {
  position: relative;
  width: 8px; height: 8px;
  cursor: pointer;
  pointer-events: auto;
}

.station-dot {
  width: 8px; height: 8px;
  border-radius: 50%;
  background: var(--green);
  border: 1.5px solid rgba(0,255,65,0.5);
  box-shadow: 0 0 6px 2px rgba(0,255,65,0.4);
}

.station-pulse {
  position: absolute;
  inset: -6px;
  border-radius: 50%;
  background: rgba(0,255,65,0.15);
  animation: globe-pulse 2.5s ease-out infinite;
}

.station-hq .station-dot {
  background: var(--warm);
  border-color: rgba(200,169,110,0.6);
  box-shadow: 0 0 8px 2px rgba(200,169,110,0.5);
}

.station-hq .station-pulse {
  background: rgba(200,169,110,0.15);
}

.station-tooltip {
  position: absolute;
  bottom: 18px; left: 50%;
  transform: translateX(-50%);
  background: rgba(0,0,0,0.85);
  border: 1px solid var(--green-dim);
  padding: 6px 10px;
  white-space: nowrap;
  font-family: var(--font-mono);
  font-size: 9px;
  letter-spacing: 0.1em;
  text-transform: uppercase;
  color: var(--green);
  opacity: 0;
  transition: opacity 0.15s;
  pointer-events: none;
}

.station-marker:hover .station-tooltip {
  opacity: 1;
}

@keyframes globe-pulse {
  0% { transform: scale(1); opacity: 0.6; }
  100% { transform: scale(3); opacity: 0; }
}

/* ── Responsive: Mobile ───────────────────────────────────── */
@media (max-width: 768px) {
  .hud-top {
    flex-direction: column;
    gap: 10px;
    padding: 16px;
  }

  .hud-coords {
    text-align: left;
  }

  .hud-bottom {
    flex-direction: column;
    align-items: flex-start;
    gap: 16px;
    padding: 16px;
    padding-bottom: 28px;
  }

  .identity-block {
    max-width: 100%;
  }

  .id-name { font-size: 18px; }
  .id-title { font-size: 10px; }
  .svc-item { font-size: 9px; }

  /* Hide QR on mobile — can't scan your own phone */
  .qr-block {
    display: none;
  }

  .actions-col {
    width: 100%;
    align-items: flex-start;
  }

  .actions-block {
    flex-direction: row;
    flex-wrap: wrap;
    align-items: flex-start;
    width: 100%;
  }

  .action-btn {
    font-size: 9px;
    padding: 5px 10px;
  }

  .classification-bar {
    font-size: 8px;
    padding: 4px 0;
  }
}

/* ── Reduced motion ───────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .station-pulse { animation: none; }
  .status-dot { animation: none; }
}

