  .id-title { font-size: 10px; }
  .svc-item { font-size: 9px; }

  /* Hide QR on mobile — can't scan your own phone */
  .qr-block {
    display: none;
  }

  .actions-col {
    width: 100%;
    align-items: flex-start;
  }

  .actions-block {
    flex-direction: row;
    flex-wrap: wrap;
    align-items: flex-start;
    width: 100%;
  }

  .action-btn {
    font-size: 9px;
    padding: 5px 10px;
  }

  .classification-bar {
    font-size: 8px;
    padding: 4px 0;
  }
}

/* ── Reduced motion ───────────────────────────────────────── */
@media (prefers-reduced-motion: reduce) {
  .station-pulse { animation: none; }
  .status-dot { animation: none; }
}

