      'position:absolute;top:0;left:0;width:100%!important;height:100%!important;';
  }

  /* ── Load country polygons ──────────────────────────────── */
  let countries: any[] = [];
  try {
    const resp = await fetch('/countries-110m.json');
    const topo = await resp.json();
    const geo = topojson.feature(topo, topo.objects.countries);
    countries = geo.features || [];
  } catch (e) {
    console.warn('[GLOBE] Failed to load country data:', e);
  }

  /* ── Country polygons — BRIGHT outlines, subtle fill ────── */
  (globe as any)
    .polygonsData(countries)
    .polygonGeoJsonGeometry((d: any) => d.geometry)
    .polygonCapColor(() => 'rgba(0,255,65,0.06)')
    .polygonSideColor(() => 'rgba(0,255,65,0.03)')
    .polygonStrokeColor(() => 'rgba(0,255,65,0.4)')
    .polygonAltitude(0.006)
    .polygonsTransitionDuration(0);

  /* ── Graticule grid — visible ───────────────────────────── */
  const graticule = generateGraticule(30);
  (globe as any)
    .pathsData(graticule)
    .pathPoints((d: GraticulePath) => d.coords)
    .pathPointLat((p: { lat: number; lng: number }) => p.lat)
    .pathPointLng((p: { lat: number; lng: number }) => p.lng)
    .pathColor(() => 'rgba(0,255,65,0.12)')
    .pathStroke(0.4)
    .pathDashLength(999)
    .pathDashGap(0)
    .pathTransitionDuration(0);

  /* ── Station points — BIG glowing dots ──────────────────── */
  const stationPoints = STATIONS.map(s => ({
    lat: s.lat, lng: s.lng, city: s.city, isHQ: s.isHQ || false,
  }));

  (globe as any)
    .pointsData(stationPoints)
    .pointLat((d: any) => d.lat)
    .pointLng((d: any) => d.lng)
    .pointColor((d: any) => d.isHQ ? '#00ff41' : '#00dd38')
    .pointAltitude(0.015)
    .pointRadius((d: any) => d.isHQ ? 0.5 : 0.3)
    .pointResolution(16)
    .pointsMerge(false);

  /* ── Station pulse rings — AGGRESSIVE ───────────────────── */
  const stationRings = STATIONS.map(s => ({
    lat: s.lat, lng: s.lng, isHQ: s.isHQ || false,
  }));

  (globe as any)
    .ringsData(stationRings)
    .ringLat((d: any) => d.lat)
    .ringLng((d: any) => d.lng)
    .ringColor(() => (t: number) => `rgba(0,255,65,${(1 - t) * 0.8})`)
    .ringMaxRadius((d: any) => d.isHQ ? 5 : 3)
    .ringPropagationSpeed((d: any) => d.isHQ ? 3 : 2)
    .ringRepeatPeriod((d: any) => d.isHQ ? 800 : 1400);

  /* ── Communication arcs — HOT green ─────────────────────── */
  const arcs = generateArcs();
  const greenArcs = arcs.map(a => ({
    ...a,
    color: [
      `${ARC_GREEN}0.08)`,
      `${ARC_GREEN}0.7)`,
      `${ARC_GREEN}0.08)`,
    ] as [string, string, string],
  }));

  (globe as any)
    .arcsData(greenArcs)
    .arcStartLat((d: CommArc) => d.startLat)
    .arcStartLng((d: CommArc) => d.startLng)
    .arcEndLat((d: CommArc) => d.endLat)
    .arcEndLng((d: CommArc) => d.endLng)
    .arcColor((d: CommArc) => d.color)
    .arcAltitudeAutoScale(0.35)
    .arcStroke(0.5)
    .arcDashLength(0.8)
    .arcDashGap(2)
    .arcDashAnimateTime(2000);

  /* ── Orbit controls ─────────────────────────────────────── */
  const controls = globe.controls() as any;
  controls.autoRotate = true;
  controls.autoRotateSpeed = 0.25;
  controls.enablePan = false;
  controls.enableZoom = false;
  controls.enableDamping = true;

  /* ── Camera ─────────────────────────────────────────────── */
  globe.pointOfView({ lat: 38, lng: 15, altitude: 2.2 }, 0);
  globeInstance = globe;

  /* ── Pause/resume auto-rotate ───────────────────────────── */
  if (canvas) {
    const pause = () => {
      controls.autoRotate = false;
      if (autoRotateTimer) clearTimeout(autoRotateTimer);
    };
    const resume = () => {
      if (autoRotateTimer) clearTimeout(autoRotateTimer);
      autoRotateTimer = setTimeout(() => { controls.autoRotate = true; }, 30_000);
    };
    canvas.addEventListener('mousedown', pause);
    canvas.addEventListener('touchstart', pause, { passive: true });
    canvas.addEventListener('mouseup', resume);
    canvas.addEventListener('touchend', resume);
  }

  /* ── Enhanced scene objects ─────────────────────────────── */
  addGlowSphere(scene);
  addStarField(scene);

  /* ── Resize ─────────────────────────────────────────────── */
  window.addEventListener('resize', () => {
    globe.width(container.clientWidth || window.innerWidth);
    globe.height(container.clientHeight || window.innerHeight);
  });

  /* ── WebGL recovery ─────────────────────────────────────── */
  if (canvas) {
    canvas.addEventListener('webglcontextlost', (e) => {
      e.preventDefault();
      container.style.background = '#000';
    });
  }
}

/* ── Outer glow sphere — green halo around globe ──────────── */
function addGlowSphere(scene: any): void {
  // Outer glow — green BackSide mesh
  const outerGeo = new THREE.SphereGeometry(2.2, 64, 64);
  const outerMat = new THREE.MeshBasicMaterial({
    color: 0x00ff41,
    side: THREE.BackSide,
    transparent: true,
    opacity: 0.08,
  });
  const outerGlow = new THREE.Mesh(outerGeo, outerMat);
  scene.add(outerGlow);

  // Inner glow — tighter, brighter
  const innerGeo = new THREE.SphereGeometry(2.08, 64, 64);
  const innerMat = new THREE.MeshBasicMaterial({
    color: 0x00ff41,
    side: THREE.BackSide,
    transparent: true,
    opacity: 0.05,
  });
  const innerGlow = new THREE.Mesh(innerGeo, innerMat);
  scene.add(innerGlow);

  // Animate glow rotation
  const animate = () => {
    outerGlow.rotation.y += 0.0004;
    innerGlow.rotation.y -= 0.0002;
    requestAnimationFrame(animate);
  };
  animate();
}

/* ── Star field — brighter, more visible ──────────────────── */
function addStarField(scene: any): void {
  const starCount = 2500;
  const positions = new Float32Array(starCount * 3);
  const colors = new Float32Array(starCount * 3);

  for (let i = 0; i < starCount; i++) {
    const r = 40 + Math.random() * 60;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.acos(2 * Math.random() - 1);
    positions[i * 3]     = r * Math.sin(phi) * Math.cos(theta);
    positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    positions[i * 3 + 2] = r * Math.cos(phi);

    // Green-tinted stars — brighter than before
    const brightness = 0.3 + Math.random() * 0.5;
    colors[i * 3]     = brightness * 0.4;
    colors[i * 3 + 1] = brightness;
    colors[i * 3 + 2] = brightness * 0.4;
  }

  const starGeo = new THREE.BufferGeometry();
  starGeo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
  starGeo.setAttribute('color', new THREE.BufferAttribute(colors, 3));

  const starMat = new THREE.PointsMaterial({
    size: 0.12,
    vertexColors: true,
    transparent: true,
    opacity: 0.8,
  });

  const starField = new THREE.Points(starGeo, starMat);
  scene.add(starField);

  const animate = () => {
    starField.rotation.y += 0.00003;
    requestAnimationFrame(animate);
  };
  animate();
}

