### 5. **arcs.ts** (58 lines - Network Visualization)

```typescript
export function generateArcs(): CommArc[] {
  const hq = STATIONS.find(s => s.isHQ)!;              // London
  const others = STATIONS.filter(s => !s.isHQ);

  // HQ → all stations
  const hqArcs: CommArc[] = others.map(s => makeArc(hq, s, 'primary'));

  // Inter-station links (visual density control)
  const interPairs: [string, string][] = [
    ['BUCHAREST', 'CLUJ'],
    ['BUCHAREST', 'DUBAI'],
    ['AMSTERDAM', 'BUCHAREST'],
    ['UK SOUTH', 'AMSTERDAM'],
  ];

  const interArcs: CommArc[] = interPairs
    .map(([a, b]) => {
      const sa = STATIONS.find(s => s.city === a);
      const sb = STATIONS.find(s => s.city === b);
      if (sa && sb) return makeArc(sa, sb, 'secondary');
      return null;
    })
    .filter((a): a is CommArc => a !== null);

  return [...hqArcs, ...interArcs];
}

function makeArc(from: Station, to: Station, type: 'primary' | 'secondary'): CommArc {
  const colors: Record<string, [string, string, string]> = {
    primary: ['rgba(68,136,255,0.05)', 'rgba(68,136,255,0.5)', 'rgba(68,136,255,0.05)'],
    secondary: ['rgba(0,212,255,0.03)', 'rgba(0,212,255,0.25)', 'rgba(0,212,255,0.03)'],
  };

  return {
    startLat: from.lat,
    startLng: from.lng,
    endLat: to.lat,
    endLng: to.lng,
    color: colors[type],  // Tri-color gradient (faded → bright → faded)
  };
}
```

**Pattern:** Generator + factory. Tri-color arc gradients for depth perception.

