export const VCARD_STRING = `BEGIN:VCARD
VERSION:3.0
FN:Nicolae Fratila
N:Fratila;Nicolae;;;
ORG:APEX OS / NFG Digital Solutions Ltd
TITLE:Founder & CEO — Sovereign AI Infrastructure
