X-SOCIALPROFILE;TYPE=linkedin:https://linkedin.com/in/nicofratila
X-SOCIALPROFILE;TYPE=github:https://github.com/fratilanico
X-SOCIALPROFILE;TYPE=twitter:https://x.com/nicofratila
END:VCARD`;

export function downloadVCard(): void {
  const blob = new Blob([VCARD_STRING], { type: 'text/vcard;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'Nico_Fratila_APEX_OS.vcf';
  document.body.appendChild(a);
  a.click();
  setTimeout(() => {
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  }, 100);
}
```

**Pattern:** vCard 3.0 standard format. Client-side Blob download (no server).

