"use client";

import { useEffect, useRef, useState } from "react";

interface Props {
  to: number;
  duration?: number;
  prefix?: string;
  suffix?: string;
  decimals?: number;
}

export default function AnimatedCounter({ to, duration = 1800, prefix = "", suffix = "", decimals = 0 }: Props) {
  const [value, setValue] = useState(0);
  const ref = useRef<HTMLSpanElement>(null);
  const started = useRef(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !started.current) {
          started.current = true;
          const start = performance.now();
          const tick = (now: number) => {
            const elapsed = now - start;
            const progress = Math.min(elapsed / duration, 1);
            // Ease out cubic
            const eased = 1 - Math.pow(1 - progress, 3);
            setValue(parseFloat((eased * to).toFixed(decimals)));
            if (progress < 1) requestAnimationFrame(tick);
          };
          requestAnimationFrame(tick);
        }
      },
      { threshold: 0.4 }
    );

    observer.observe(el);
    return () => observer.disconnect();
  }, [to, duration, decimals]);

  return (
    <span ref={ref}>
      {prefix}{decimals > 0 ? value.toFixed(decimals) : Math.floor(value).toLocaleString()}{suffix}
    </span>
  );
}

"use client";

const stats = [
  { label: "Products Shipped", value: "10" },
  { label: "Tests Across Fleet", value: "7,000+" },
  { label: "Workers Active", value: "13" },
  { label: "Manual Restarts", value: "0" },
  { label: "Knowledge Briefs", value: "161" },
  { label: "Skills Registered", value: "139+" },
  { label: "Companies Scored", value: "19,413" },
  { label: "Governance Lines", value: "11,721" },
];

const items = [...stats, ...stats];

export default function StatsTicker() {
  return (
    <div className="bg-[#1d1d1f] py-4 overflow-hidden border-y border-[#2d2d2f]">
      <div className="flex items-center gap-0 animate-ticker whitespace-nowrap w-max">
        {items.map((stat, i) => (
          <span key={i} className="inline-flex items-center gap-2 px-8">
            <span className="text-[#0071e3] font-bold text-[15px]">{stat.value}</span>
            <span className="text-[#86868b] text-[13px] uppercase tracking-widest font-medium">{stat.label}</span>
            <span className="text-[#3d3d3f] mx-4 select-none">·</span>
          </span>
        ))}
      </div>
    </div>
  );
}

